import React, { useContext, useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { AuthContext } from '../App';
import { API_URL } from '../config';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';

const Dashboard = () => {
  const { token, logout } = useContext(AuthContext);
  const [workouts, setWorkouts] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchWorkouts = async () => {
      try {
        const res = await fetch(`${API_URL}/api/workouts`, {
          headers: { 'x-auth-token': token },
        });
        const data = await res.json();
        if (res.ok) setWorkouts(data);
      } catch (err) {
        console.error(err);
      }
    };
    if (token) fetchWorkouts();
  }, [token]);

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this workout?')) return;
    try {
      const res = await fetch(`${API_URL}/api/workouts/${id}`, {
        method: 'DELETE',
        headers: { 'x-auth-token': token },
      });
      if (res.ok) {
        setWorkouts(workouts.filter((w) => w._id !== id));
      }
    } catch (err) {
      console.error(err);
    }
  };

  // Prepare data for chart (example: total weight lifted per session)
  const chartData = workouts.map((w) => ({
    date: new Date(w.date).toLocaleDateString(),
    totalWeight: w.sets.reduce((acc, s) => acc + s.weight * s.reps, 0),
  })).reverse();

  return (
    <div>
      <nav className="nav">
        <h1>Fitness Tracker</h1>
        <div>
          <Link to="/add">Add Workout</Link>
          <button className="secondary" onClick={logout} style={{ marginLeft: '10px' }}>Sign Out</button>
        </div>
      </nav>

      <div className="chart-container" style={{ height: 400, marginTop: 40, marginBottom: 40 }}>
        <h3>Progress Chart</h3>
        <ResponsiveContainer width="100%" height="80%">
          <LineChart data={chartData}>
            <CartesianGrid strokeDasharray="3 3" />
            <XAxis dataKey="date" />
            <YAxis />
            <Tooltip />
            <Legend />
            <Line type="monotone" dataKey="totalWeight" stroke="#8884d8" />
          </LineChart>
        </ResponsiveContainer>
      </div>

      <h2>Workout History</h2>
      {workouts.length === 0 ? (
        <p style={{color: 'var(--apple-text-secondary)'}}>No workouts recorded yet. Get moving!</p>
      ) : (
        <div className="workouts-grid">
          {workouts.map((w) => (
            <div key={w._id} className="workout-item">
              <h4>{new Date(w.date).toLocaleDateString()} - {w.exercise}</h4>
              <ul>
                {w.sets.map((s, i) => (
                  <li key={i}>{s.weight}kg x {s.reps}</li>
                ))}
              </ul>
              {w.notes && <p>Notes: {w.notes}</p>}
              <button className="secondary" onClick={() => handleDelete(w._id)}>Delete</button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default Dashboard;
